//! Quality gate: prove a real Qwen model answers "Paris" through the full
//! monster-swarm path — UCAN-verified spawn of a `fat-station` subagent on the
//! local mesh, queried over the wire — not synthetic/"fake agent" plumbing.
//!
//! This is the base-completion form on purpose: a coder model will deflect a
//! chat question ("I'm a coding assistant…"), but at the token level it still
//! completes "The capital of France is" → " Paris". So we assert the next
//! token, immune to chat-template refusals.
//!
//! Heavy + gated: it spawns a 7B fat-station and runs real CPU forwards (~2 min).
//! It SKIPS (passes) unless a dense Qwen knot and the binaries are present, so
//! plain `cargo test` stays light. Enable by having either:
//!   - `$MONSTER_SWARM_QWEN_KNOT` pointing at a dense Qwen `.knot`, or
//!   - `~/.edgework/models/qwen-coder-7b.knot` on disk,
//! plus release builds of `fat-station` and `monster-guard`.

use std::io::{Read, Write};
use std::net::TcpStream;
use std::path::PathBuf;
use std::time::{Duration, Instant};

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions};

use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, SpawnRequest};
use monster_swarm::store;

/// "The capital of France is" in the Qwen2.5 tokenizer.
const PROMPT: &[usize] = &[785, 6722, 315, 9625, 374];
/// " Paris" — the correct next token (verified via the Qwen tokenizer; the
/// repo README's "279" was a doc error — 279 is " the").
const PARIS: u64 = 12095;
const PORT: u16 = 8779;

fn manifest_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
}

/// The dense Qwen knot, or None to skip.
fn knot_path() -> Option<PathBuf> {
    if let Ok(p) = std::env::var("MONSTER_SWARM_QWEN_KNOT") {
        let pb = PathBuf::from(p);
        return pb.exists().then_some(pb);
    }
    let home = std::env::var("HOME").ok()?;
    let pb = PathBuf::from(home).join(".edgework/models/qwen-coder-7b.knot");
    pb.exists().then_some(pb)
}

/// Resolve a sibling crate's release/debug binary, or None.
fn sibling_bin(crate_rel: &str, name: &str) -> Option<PathBuf> {
    for profile in ["release", "debug"] {
        let p = manifest_dir().join(format!("../{crate_rel}/target/{profile}/{name}"));
        if p.exists() {
            return Some(p);
        }
    }
    None
}

fn http_health(port: u16) -> bool {
    let Ok(mut s) = TcpStream::connect(("127.0.0.1", port)) else {
        return false;
    };
    let _ = s.set_read_timeout(Some(Duration::from_secs(5)));
    let req = format!("GET /health HTTP/1.1\r\nHost: 127.0.0.1\r\nConnection: close\r\n\r\n");
    if s.write_all(req.as_bytes()).is_err() {
        return false;
    }
    let mut buf = String::new();
    let _ = s.read_to_string(&mut buf);
    buf.starts_with("HTTP/1.1 200") || buf.contains(" 200 ")
}

/// One `/decode-next` step: feed `token` at `pos`, return the predicted next id.
fn decode_next(port: u16, token: usize, pos: usize) -> u64 {
    let mut s = TcpStream::connect(("127.0.0.1", port)).expect("connect fat-station");
    // A 7B CPU forward is slow; give it ample room.
    s.set_read_timeout(Some(Duration::from_secs(120))).unwrap();
    let req = format!(
        "POST /decode-next HTTP/1.1\r\nHost: 127.0.0.1\r\nX-Token: {token}\r\nX-Position: {pos}\r\nContent-Length: 0\r\nConnection: close\r\n\r\n"
    );
    s.write_all(req.as_bytes()).unwrap();
    let mut resp = String::new();
    s.read_to_string(&mut resp).unwrap();
    let body = resp
        .split_once("\r\n\r\n")
        .map(|(_, b)| b)
        .unwrap_or("")
        .trim();
    let v: serde_json::Value =
        serde_json::from_str(body).unwrap_or_else(|e| panic!("bad /decode-next JSON ({e}): {body}"));
    v.get("token_id")
        .and_then(|t| t.as_u64())
        .unwrap_or_else(|| panic!("no token_id in response: {body}"))
}

#[test]
fn qwen_says_paris_through_a_leased_subagent() {
    // ---- gate -----------------------------------------------------------
    let Some(knot) = knot_path() else {
        eprintln!("SKIP: no dense Qwen knot (set $MONSTER_SWARM_QWEN_KNOT or place ~/.edgework/models/qwen-coder-7b.knot)");
        return;
    };
    let Some(guard) = sibling_bin("monster-guard", "monster-guard") else {
        eprintln!("SKIP: monster-guard not built (cargo build --release in ../monster-guard)");
        return;
    };
    let Some(fat) = sibling_bin("distributed-inference", "fat-station") else {
        eprintln!("SKIP: fat-station not built (cargo build --release --bin fat-station in ../distributed-inference)");
        return;
    };

    // ---- isolated shared state + node allowlist -------------------------
    let home = std::env::temp_dir().join(format!("monster-swarm-paris-{}", std::process::id()));
    let _ = std::fs::create_dir_all(&home);
    std::env::set_var("MONSTER_GUARD_HOME", &home);
    std::env::set_var("MONSTER_GUARD_BIN", &guard);
    std::env::set_var("MONSTER_SWARM_NODES", fat.parent().unwrap());

    // ---- mint a root-rooted capability granting agent/spawn -------------
    let root = store::ensure_root().expect("root");
    let cap = Capability {
        can: "agent/spawn".into(),
        with: "agent:fleet".into(),
        constraints: None,
    };
    let token = issue(&root, root.did(), &[cap], 3600, &IssueOptions::default()).expect("issue ucan");

    // ---- spawn fat-station as a leased subagent on the mesh -------------
    // Short lease: it auto-renews while we query, and dies promptly on reap.
    let req = SpawnRequest {
        ucan: token.clone(),
        node: "fat-station".into(),
        id: Some("paris".into()),
        caste: Caste::Scout,
        caps: vec!["net".into()],
        lease_secs: 15,
        max_secs: None,
        grant_ttl_secs: 3600,
        node_args: vec![
            "--knot".into(),
            knot.to_string_lossy().into_owned(),
            "--port".into(),
            PORT.to_string(),
            "--role".into(),
            "both".into(),
            "--layers".into(),
            "0..28".into(),
        ],
        qspec: None,
        oath: None,
        teleport: None,
    };
    let spawned = ops::spawn(req).expect("spawn fat-station subagent");
    eprintln!("[paris] spawned subagent '{}' pid {}", spawned.id, spawned.pid);

    // ---- wait for the mesh node to be ready ----------------------------
    let started = Instant::now();
    let mut ready = false;
    while started.elapsed() < Duration::from_secs(180) {
        if http_health(PORT) {
            ready = true;
            break;
        }
        std::thread::sleep(Duration::from_secs(1));
    }

    // ---- drive the prompt through the mesh -----------------------------
    let mut last = 0u64;
    if ready {
        for (pos, &tok) in PROMPT.iter().enumerate() {
            last = decode_next(PORT, tok, pos);
        }
    }

    // ---- always reap (revoke -> killed at next lease tick) -------------
    let _ = ops::reap(&token, "paris");
    let _ = std::fs::remove_dir_all(&home);

    assert!(ready, "fat-station subagent never became ready on :{PORT}");
    assert_eq!(
        last, PARIS,
        "mesh predicted token {last}, expected {PARIS} (\" Paris\") — quality regression"
    );
    eprintln!("[paris] OK: mesh predicted token {last} = \" Paris\"");
}
